mapper.insert:
INSERT INTO tutor_student_note (
    id, tutor_id, student_id, progress, notes
) VALUES (
    UUID(), #{tutorId}, #{studentId}, #{progress}, #{notes}
)
ON DUPLICATE KEY UPDATE
    progress = VALUES(progress),
    notes = VALUES(notes),
    updated_at = CURRENT_TIMESTAMP

mapper.select:
SELECT id, tutor_id AS tutorId, student_id AS studentId, progress, notes, updated_at AS updatedAt
FROM tutor_student_note
WHERE tutor_id = #{tutorId}

SELECT COUNT(*)
FROM booking b
JOIN lesson l ON b.lesson_id = l.id
WHERE l.user_id = #{tutorId}
  AND b.user_id = #{studentId}
  AND b.canceled_at IS NULL
